-- ----------------------------
-- Table structure for users
-- ----------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `username` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '账号 手机号',
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码',
  `company` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '公司名称',
  `parent_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '上级 ID',
  `master_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '品牌 ID',
  `role_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '角色 ID',
  `standing` tinyint(4) NOT NULL DEFAULT '1' COMMENT '身份 1系统管理员 2企业主账号 3企业子账号 4海关',
  `enterprise` tinyint(4) NOT NULL DEFAULT '1' COMMENT '审核标准1通用 2通用 + 单项',
  `login_at` datetime DEFAULT NULL COMMENT '最近登录时间',
  `note` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `users_parent_id_index` (`parent_id`),
  KEY `users_master_id_index` (`master_id`),
  KEY `users_standing_index` (`standing`),
  KEY `users_enterprise_index` (`enterprise`),
  KEY `users_role_id_index` (`role_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

